package com.taskmind.backend.specbreakdown.infrastructure.persistence.jpa;
import com.taskmind.backend.specbreakdown.application.SpecBreakdownProcessingJob; import com.taskmind.backend.specbreakdown.domain.repository.SpecBreakdownJobRepository; import java.util.*; import org.springframework.stereotype.Repository;
@Repository class JpaSpecBreakdownJobRepository implements SpecBreakdownJobRepository { private final SpringDataSpecBreakdownJobRepository repo; JpaSpecBreakdownJobRepository(SpringDataSpecBreakdownJobRepository repo){this.repo=repo;} public SpecBreakdownProcessingJob save(SpecBreakdownProcessingJob j){return repo.saveAndFlush(SpecBreakdownJobJpaEntity.from(j)).toDomain();} public Optional<SpecBreakdownProcessingJob> findById(UUID id){return repo.findById(id).map(SpecBreakdownJobJpaEntity::toDomain);} public List<SpecBreakdownProcessingJob> findByDraftId(UUID draftId){return repo.findByDraftIdOrderByCreatedAtDesc(draftId).stream().map(SpecBreakdownJobJpaEntity::toDomain).toList();}}
